import type { JSONSupport } from "../../core/JSONSupport.js";

export interface PointCloudFilterProperties extends Partial<Pick<PointCloudFilter, "field">> {}

export type PointCloudFilterType = "value" | "bitfield" | "return";

/**
 * Point cloud filters are used to hide points that do not satisfy the filter criteria.
 *
 * There are two types of filters that can be assigned to [PointCloudLayer.filters](https://developers.arcgis.com/javascript/latest/references/core/layers/PointCloudLayer/#filters):
 *
 * [PointCloudValueFilter](https://developers.arcgis.com/javascript/latest/references/core/layers/pointCloudFilters/PointCloudValueFilter/) is useful for filtering points based
 * on their classification value. If only the points that represent ground and buildings should be displayed,
 * the following filter can be set:
 *
 * ```js
 * const pcLayer = new PointCloudLayer({
 *   ...,
 *   filters: [{
 *     type: "value",
 *     field: "CLASS_CODE",
 *     mode: "include",
 *     // values include ground(2) and building(6)
 *     values: [2, 6]
 *   }]
 * });
 * ```
 *
 * [PointCloudReturnFilter](https://developers.arcgis.com/javascript/latest/references/core/layers/pointCloudFilters/PointCloudReturnFilter/) is used to filter points based on the return value
 * stored with each point in the `RETURNS` field. The following filter can be set to display only the points that represent the highest feature in
 * a landscape:
 *
 * ```js
 * const pointCloudLayer = new PointCloudLayer({
 *  ...,
 *  filters: [{
 *    type: "return",
 *    field: "RETURNS",
 *    values: ["firstOfMany", "single"]
 *  }]
 * });
 * ```
 *
 * Filters can also be combined by setting several filters on one layer. Only points that satisfy all filters are displayed.
 *
 * @since 4.10
 * @see [Sample - Filter points in a PointCloudLayer](https://developers.arcgis.com/javascript/latest/sample-code/layers-pointcloud-filters/)
 * @see [PointCloudLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/PointCloudLayer/)
 * @see [PointCloudReturnFilter](https://developers.arcgis.com/javascript/latest/references/core/layers/pointCloudFilters/PointCloudReturnFilter/)
 * @see [PointCloudValueFilter](https://developers.arcgis.com/javascript/latest/references/core/layers/pointCloudFilters/PointCloudValueFilter/)
 */
export default class PointCloudFilter extends JSONSupport {
  constructor(properties?: PointCloudFilterProperties);
  /** The field used for applying the filter. */
  accessor field: string | null | undefined;
  /** The type of filter. */
  get type(): PointCloudFilterType;
}